// ============================================================
// EXTRACTDATA v13.3 - WF1 2-STEP APPROVAL WITH PSYCHOLOGY
// ============================================================
// Purpose: Extract and validate clarification data for email workflow
// Mode: Run Once for All Items
// Version: 13.3 - Added psychology effects + T2 fallback to title
// ============================================================

const items = $input.all();
const results = [];

// ============================================================
// CONSTANTS
// ============================================================

const ALWAYS_CC = ['hoangkha@esuhai.com', 'vynnl@esuhai.com'];

// ============================================================
// HELPER FUNCTIONS
// ============================================================

function safeText(arr) {
  if (!Array.isArray(arr) || arr.length === 0) return '';
  return arr.map(t => t.plain_text || '').join('');
}

function safeSelect(select) {
  if (!select || !select.name) return '';
  return select.name;
}

function safeDate(date) {
  if (!date || !date.start) return '';
  return date.start;
}

function safeRelation(relation) {
  if (!Array.isArray(relation) || relation.length === 0) return null;
  return relation[0]; // Return first relation object
}

function safeRollup(rollup) {
  if (!rollup || rollup.type !== 'array' || !Array.isArray(rollup.array)) return '';
  if (rollup.array.length === 0) return '';
  const firstItem = rollup.array[0];
  if (firstItem.type === 'email') return firstItem.email || '';
  if (firstItem.type === 'rich_text') return safeText(firstItem.rich_text);
  return '';
}

// ============================================================
// PROCESS EACH ITEM
// ============================================================

for (let i = 0; i < items.length; i++) {
  const item = items[i];
  const page = item.json;
  const props = page.properties || {};

  // ==========================================
  // EXTRACT BASIC INFO
  // ==========================================

  const id = page.id;
  const tieuDe = safeText(props['Tiêu đề']?.title);
  const nguon = safeSelect(props['Nguồn']?.select);
  const ngayNhan = safeDate(props['Ngày nhận']?.date);
  const noiDung = safeText(props['Nội dung gốc']?.rich_text);

  // ==========================================
  // EXTRACT STATUS & APPROVAL
  // ==========================================

  const tinhTrang = safeSelect(props['TÌNH TRẠNG']?.select);
  const daDuyet = safeSelect(props['✅ Đã duyệt bởi người chỉ đạo']?.select);
  const lenhGuiLoiNhac = safeSelect(props['LỆNH GỬI LỜI NHẮC']?.select);

  // ==========================================
  // EXTRACT NGƯỜI CHỈ ĐẠO (REQUIRED FOR STEP1)
  // ==========================================

  const nguoiChiDaoRelation = safeRelation(props['Người chỉ đạo']?.relation);
  const emailNguoiChiDao = safeRollup(props['Email người chỉ đạo']?.rollup);
  const tenNguoiChiDao = safeText(props['Tên người chỉ đạo']?.rollup?.array?.[0]?.title || []);

  // ==========================================
  // EXTRACT ĐẦU MỐI (REQUIRED FOR STEP2)
  // ==========================================

  const dauMoiRelation = safeRelation(props['T1 - ĐẦU MỐI']?.relation);
  const emailDauMoi = safeRollup(props['Email đầu mối']?.rollup);
  const tenDauMoi = safeText(props['Tên đầu mối']?.rollup?.array?.[0]?.title || []);

  // ==========================================
  // EXTRACT 4T
  // ==========================================

  const t2NhiemVu = safeText(props['T2 - NHIỆM VỤ']?.rich_text);
  const t3ChiTieu = safeText(props['T3 - CHỈ TIÊU']?.rich_text);
  const t4ThoiHan = safeDate(props['T4 - THỜI HẠN']?.date);

  // ==========================================
  // VALIDATION & ROUTING LOGIC
  // ==========================================

  // CRITICAL: Nếu không có email người chỉ đạo → SKIP với warning
  if (!emailNguoiChiDao || emailNguoiChiDao === '') {
    results.push({
      json: {
        clarificationId: id,
        warning: true,
        error: 'MISSING_NGUOI_CHI_DAO',
        message: `[${tieuDe}] Thiếu Email người chỉ đạo - Không thể gửi mail STEP1`,
        tieuDe,
        tinhTrang,
        daDuyet,
        // For WF Logs
        logStatus: '⚠️ Warning',
        logError: 'Missing: Email người chỉ đạo',
        logDetails: `ID: ${id}, Title: ${tieuDe}`,
        sendTo: '',
        emailSubject: '',
        url: page.url,
        version: '13.3'
      }
    });
    continue; // Skip to next item
  }

  // ==========================================
  // DETERMINE STEP & BUILD EMAIL
  // ==========================================

  let step = '';
  let sendTo = '';
  let emailSubject = '';
  let emailBody = '';
  let ccTo = [];

  if (!daDuyet || daDuyet === '' || daDuyet === 'Chưa duyệt') {
    // ========================================
    // STEP 1: Gửi người chỉ đạo để duyệt
    // ========================================

    step = 'STEP1';
    sendTo = emailNguoiChiDao; // Đã validate ở trên, chắc chắn có
    emailSubject = `[Cần Duyệt] ${tieuDe || 'Chỉ đạo mới'}`;
    ccTo = ALWAYS_CC.filter(e => e !== sendTo);

    emailBody = `
Kính gửi ${tenNguoiChiDao || 'Anh/Chị'},

🎯 **YÊU CẦU DUYỆT CHỈ ĐẠO QUAN TRỌNG**

Trong cuộc họp ${nguon} ngày ${ngayNhan}, Anh/Chị đã đưa ra chỉ đạo sau:

📋 **NỘI DUNG:**
${noiDung}

---

📝 **PHÂN TÍCH SƠ BỘ (Cần Anh/Chị xác nhận):**

• **T1 - ĐẦU MỐI:** ${tenDauMoi || '❓ Cần xác nhận'}
• **T2 - NHIỆM VỤ:** ${t2NhiemVu || tieuDe || '❓ Cần xác nhận'}
• **T3 - CHỈ TIÊU:** ${t3ChiTieu || '❓ Cần xác nhận'}  
• **T4 - THỜI HẠN:** ${t4ThoiHan || '❓ Cần xác nhận'}

---

💡 **TẠI SAO CẦN DUYỆT:**

✅ **Đảm bảo chính xác:** Anh/Chị xác nhận lại thông tin trước khi giao cho đầu mối
✅ **Tiết kiệm thời gian:** ${tenDauMoi || 'Đầu mối'} sẽ nhận được hướng dẫn rõ ràng, không phải hỏi lại
✅ **Theo dõi tiến độ:** CEO sẽ nhìn thấy tiến độ xử lý chỉ đạo của Anh/Chị

---

👉 **DUYỆT NGAY TẠI ĐÂY:** ${page.url}

⏰ **Chúng tôi đã BẮT ĐẦU xử lý chỉ đạo này.** Sau khi Anh/Chị duyệt, hệ thống sẽ tự động gửi email cho ${tenDauMoi || 'đầu mối'} để triển khai ngay.

---

_Trân trọng,_
_Hệ thống WF1 v13.3 - EsuhaiGroup_
_📧 Hỗ trợ: hoangkha@esuhai.com_
    `.trim();

  } else if (daDuyet === 'Đã duyệt') {
    // ========================================
    // STEP 2: Gửi đầu mối để làm rõ
    // ========================================

    // VALIDATION: Nếu không có email đầu mối → SKIP
    if (!emailDauMoi || emailDauMoi === '') {
      results.push({
        json: {
          clarificationId: id,
          warning: true,
          error: 'MISSING_DAU_MOI',
          message: `[${tieuDe}] Đã duyệt nhưng thiếu Email đầu mối - Không thể gửi mail STEP2`,
          tieuDe,
          emailNguoiChiDao,
          tenNguoiChiDao,
          tinhTrang,
          daDuyet,
          // For WF Logs
          logStatus: '⚠️ Warning',
          logError: 'Missing: Email đầu mối',
          logDetails: `ID: ${id}, Title: ${tieuDe}, Người chỉ đạo: ${tenNguoiChiDao}`,
          sendTo: '',
          emailSubject: '',
          url: page.url,
          version: '13.3'
        }
      });
      continue; // Skip to next item
    }

    step = 'STEP2';
    sendTo = emailDauMoi;
    emailSubject = `[Cần Làm Rõ] ${tieuDe || 'Chỉ đạo'} - Hạn: ${t4ThoiHan || 'Chưa xác định'}`;

    // CC: người chỉ đạo + ALWAYS_CC
    const ccList = new Set(ALWAYS_CC);
    if (emailNguoiChiDao) ccList.add(emailNguoiChiDao);
    ccList.delete(sendTo); // Remove sendTo from CC
    ccTo = Array.from(ccList);

    emailBody = `
Kính gửi ${tenDauMoi || 'Anh/Chị'},

🎯 **NHIỆM VỤ MỚI TỪ ${tenNguoiChiDao || 'LÃNH ĐẠO'}**

${tenNguoiChiDao || 'Lãnh đạo'} đã **PHÊ DUYỆT** và giao nhiệm vụ sau cho em:

📋 **NỘI DUNG:**
${noiDung}

---

📝 **YÊU CẦU CỤ THỂ (4T):**

• **T1 - ĐẦU MỐI:** ${tenDauMoi || 'Em'} (đã được chỉ định)
• **T2 - NHIỆM VỤ:** ${t2NhiemVu || tieuDe || 'Cần em xác nhận'}
• **T3 - CHỈ TIÊU:** ${t3ChiTieu || 'Cần em xác nhận'}  
• **T4 - THỜI HẠN:** ${t4ThoiHan || 'Cần em xác nhận'}

---

💡 **TẠI SAO CẦN XÁC NHẬN:**

✅ **Làm rõ kỳ vọng:** Đảm bảo em hiểu đúng yêu cầu của ${tenNguoiChiDao || 'lãnh đạo'}
✅ **Cam kết có ý thức:** "Người Nói Phải LÀM" - Em xác nhận là em cam kết làm
✅ **CEO theo dõi:** Tiến độ sẽ được báo cáo trực tiếp lên CEO

---

👉 **XÁC NHẬN 4T NGAY:** ${page.url}

⏰ **Chúng tôi đã BẮT ĐẦU tạo Task cho em.** Sau khi em xác nhận đầy đủ 4T, hệ thống sẽ hoàn tất Task và em có thể bắt đầu thực hiện ngay.

🏆 **Đồng nghiệp khác đã xác nhận 4T trong vòng 24h.** Em cũng làm được!

---

_Trân trọng,_
_Hệ thống WF1 v13.3 - EsuhaiGroup_  
_📧 Hỗ trợ: hoangkha@esuhai.com_
    `.trim();

  } else {
    // Skip: Từ chối or other status
    continue;
  }

  // ==========================================
  // BUILD RESULT OBJECT
  // ==========================================

  results.push({
    json: {
      clarificationId: id,
      step,
      tieuDe,
      nguon,
      ngayNhan,
      noiDung,

      // People
      emailNguoiChiDao,
      tenNguoiChiDao,
      emailDauMoi,
      tenDauMoi,

      // Email routing
      sendTo,
      emailSubject,
      ccTo: ccTo.join(', '),
      emailBody,

      // Status
      tinhTrang,
      daDuyet,
      lenhGuiLoiNhac,

      // 4T
      t2NhiemVu,
      t3ChiTieu,
      t4ThoiHan,

      // URL
      url: page.url,

      // Version
      version: '13.3'
    }
  });
}

// ============================================================
// RETURN RESULTS
// ============================================================

return results;

