// ==========================================
// AGGREGATE ERRORS - Tổng hợp lỗi thành 1 email
// ==========================================

const items = $input.all();

// Filter chỉ lấy error items
const errorItems = items.filter(item => item.json.warning === true);

if (errorItems.length === 0) {
  // Không có lỗi → return empty
  return [];
}

// ==========================================
// BUILD SUMMARY TABLE
// ==========================================

let tableRows = '';

for (let i = 0; i < errorItems.length; i++) {
  const item = errorItems[i].json;
  const stt = i + 1;

  tableRows += `
<tr>
  <td style="border: 1px solid #ddd; padding: 8px; text-align: center;">${stt}</td>
  <td style="border: 1px solid #ddd; padding: 8px;">${item.tieuDe || 'Không có tiêu đề'}</td>
  <td style="border: 1px solid #ddd; padding: 8px;">${item.nguon || 'N/A'}</td>
  <td style="border: 1px solid #ddd; padding: 8px;">${item.error || 'Unknown error'}</td>
  <td style="border: 1px solid #ddd; padding: 8px;"><a href="${item.url || '#'}">Xem chi tiết</a></td>
</tr>
  `.trim();
}

// ==========================================
// BUILD EMAIL CONTENT
// ==========================================

const emailSubject = `[⚠️ Cần Xử Lý] ${errorItems.length} chỉ đạo thiếu thông tin - ${new Date().toLocaleDateString('vi-VN')}`;

const emailBody = `
<!DOCTYPE html>
<html>
<head>
  <meta charset="UTF-8">
  <style>
    body { font-family: Arial, sans-serif; line-height: 1.6; }
    table { border-collapse: collapse; width: 100%; margin: 20px 0; }
    th { background-color: #f39c12; color: white; padding: 10px; text-align: left; border: 1px solid #ddd; }
    td { border: 1px solid #ddd; padding: 8px; }
    .summary { background-color: #fff3cd; border-left: 4px solid #f39c12; padding: 15px; margin: 20px 0; }
  </style>
</head>
<body>
  <h2>⚠️ BÁO CÁO CHỈ ĐẠO THIẾU THÔNG TIN</h2>

  <div class="summary">
    <strong>Tổng quan:</strong> Hệ thống phát hiện <strong>${errorItems.length} chỉ đạo</strong> không thể xử lý do thiếu thông tin bắt buộc.
  </div>

  <h3>📋 DANH SÁCH CHI TIẾT:</h3>

  <table>
    <thead>
      <tr>
        <th style="width: 50px;">STT</th>
        <th style="width: 40%;">Tiêu đề chỉ đạo</th>
        <th style="width: 15%;">Nguồn</th>
        <th style="width: 20%;">Lỗi</th>
        <th style="width: 15%;">Link</th>
      </tr>
    </thead>
    <tbody>
      ${tableRows}
    </tbody>
  </table>

  <h3>👉 HÀNH ĐỘNG CẦN LÀM:</h3>

  <ol>
    <li><strong>Vào Notion Clarifications database</strong></li>
    <li><strong>Tìm các chỉ đạo trong bảng trên</strong></li>
    <li><strong>Cập nhật property "Người chỉ đạo"</strong> (link đến HR database)</li>
    <li><strong>Chạy lại workflow WF1</strong> (manual trigger webhook)</li>
  </ol>

  <hr style="margin: 30px 0;">

  <p style="color: #666; font-size: 12px;">
    <em>Email tự động từ Hệ thống WF1 - EsuhaiGroup</em><br>
    <em>Thời gian: ${new Date().toLocaleString('vi-VN')}</em>
  </p>
</body>
</html>
`.trim();

// ==========================================
// RETURN SINGLE AGGREGATED EMAIL
// ==========================================

return [{
  json: {
    sendTo: 'vynnl@esuhai.com, hoangkha@esuhai.com',
    emailSubject,
    emailBody,
    errorCount: errorItems.length,
    type: 'ERROR_SUMMARY',
    version: '13.1'
  }
}];

// Xử lý TẤT CẢ items
return items.map(item => {
  const data = item.json;

  // TỰ ĐỘNG XÁC ĐỊNH STATUS
  let status = "⚠️ Warning";  // Mặc định

  if (data.sendTo && data.emailSubject && data.clarificationId) {
    status = "✅ Success";  // Có đủ thông tin
  }

  if (data.logStatus) {
    status = data.logStatus;  // Ưu tiên logStatus nếu có
  }

  // Build body
  const body = {
    parent: { database_id: "53a48a4f29ba46d28e533f358d3c513c" },
    properties: {
      "Log": { 
        title: [{ 
          text: { 
            content: `WF1 - ${data.step || 'No step'}` 
          } 
        }] 
      },
      "Workflow": { 
        select: { 
          name: "WF1 - Gửi email" 
        } 
      },
      "Status": { 
        select: { 
          name: status  // ← DÙNG BIẾN ĐÃ TÍNH
        } 
      },
      "Clarification": { 
        relation: data.clarificationId ? [{ id: data.clarificationId }] : [] 
      },
      "Details": { 
        rich_text: [{ 
          text: { 
            content: data.logDetails || 
                     data.message || 
                     `ID: ${data.clarificationId}\nTitle: ${data.tieuDe}\nTo: ${data.sendTo || 'N/A'}\nSubject: ${data.emailSubject || 'N/A'}` || 
                     "No details"
          } 
        }] 
      }
    }
  };

  // Add Email To nếu có
  if (data.sendTo) {
    body.properties["Email To"] = { email: data.sendTo };
  }

  return { json: body };
});
